    23→func (r *SqrcCourseQueryService) FindCourses(ctx context.Context, keyword string, cursor string) (GetCoursesResult, error) {
    24→	var cursorUuid pgtype.UUID
    25→
    26→	if cursor != "" {
    27→		if err := cursorUuid.Scan(cursor); err != nil {
    28→			log.Printf("cursor scan error: %v", err)
    29→			return GetCoursesResult{Courses: []CoursesItem{}, Cursor: nil}, err
    30→		}
    31→	}
    32→
    33→	rawCourses, err := r.sqrc.GetCourses(ctx, db.GetCoursesParams{Cursor: cursorUuid, Keyword: keyword, Size: pageSize + 1})
    34→	if err != nil {
    35→		return GetCoursesResult{Courses: []CoursesItem{}, Cursor: nil}, err
    36→	}
    37→
    38→	slicedRawCourses := rawCourses[0:min(len(rawCourses), pageSize)]
    39→
    40→	coursesItems := make([]CoursesItem, len(slicedRawCourses))
    41→	for i, rawCourse := range slicedRawCourses {
    42→		coursesItems[i] = CoursesItem{
    43→			CourseId: rawCourse.CourseID.String(),
    44→			Title:    rawCourse.Title,
    45→		}
    46→	}
    47→
    48→	var nextCursor *string
    49→	if len(rawCourses) > pageSize {
    50→		s := rawCourses[pageSize-1].CourseID.String()
    51→		nextCursor = &s
    52→	}
    53→
    54→	return GetCoursesResult{Courses: coursesItems, Cursor: nextCursor}, nil
    55→}
